solution: class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int maxLen = 0;
        int n = s.size();
        for (int l = 0; l < n; ++l) {
            int zeros = 0, ones = 0;
            for (int r = l; r < n; ++r) {
                if (s[r] == '0') {
                    if (ones == 0) zeros++;
                    else break;
                } else {
                    ones++;
                }
                if (zeros == ones) maxLen = max(maxLen, r - l + 1);
            }
        }
        return maxLen;
    }
};
